export default async function SellerPage({
  params,
}: {
  params: Promise<{ handle: string; locale: string }>
}) {
  const { handle, locale } = await params

  const [seller, user, region] = await Promise.all([
    getSellerByHandle(handle),
    retrieveCustomer(),
    getRegion(locale),
  ])

  if (!seller) {
    notFound()
  }

  const responseMetrics = await getSellerResponseMetrics(seller.id)
  const currency_code = region?.currency_code || "usd"

  const tab = "products"

  return (
    <main className="container">
      <SellerPageHeader header seller={seller} user={user} responseMetrics={responseMetrics} />
      <SellerTabs
        tab={tab}
        seller_id={seller.id}
        seller_handle={seller.handle}
        locale={locale}
        currency_code={currency_code}
      />
    </main>
  )
}

